import { useState } from "react";

const ICONS = {
  "gasoline": "data:image/webp;base64,",
  "pliers": "data:image/webp;base64,",
  "plunger": "data:image/webp;base64,",
  "fire hydrant": "data:image/webp;base64,",
  "anvil": "data:image/webp;base64,",
  "propeller": "data:image/webp;base64,",
  "megaphone": "data:image/webp;base64,",
  "binoculars": "data:image/webp;base64,",
  "medkit": "data:image/webp;base64,",
  "duck": "data:image/webp;base64,",
  "rubber boots": "data:image/webp;base64,",
  "ammo": "data:image/webp;base64,",
};

const ITEMS = [
  { id: 1, name: "gasoline", label: "Gasoline" },
  { id: 2, name: "pliers", label: "Pliers" },
  { id: 3, name: "plunger", label: "Plunger" },
  { id: 4, name: "fire hydrant", label: "Fire Hydrant" },
  { id: 5, name: "anvil", label: "Anvil" },
  { id: 6, name: "propeller", label: "Propeller" },
  { id: 7, name: "megaphone", label: "Megaphone" },
  { id: 8, name: "binoculars", label: "Binoculars" },
  { id: 9, name: "medkit", label: "Medkit" },
  { id: 10, name: "duck", label: "Duck" },
  { id: 11, name: "rubber boots", label: "Rubber Boots" },
  { id: 12, name: "ammo", label: "Ammo" },
];


export default function InventoryTable() {
  const [quantities, setQuantities] = useState(
    Object.fromEntries(ITEMS.map(it => [it.name, ""]))
  );

  const total = Object.values(quantities).reduce(
    (sum, v) => sum + (parseInt(v) || 0), 0
  );

  return (
    <div style={{
      minHeight: "100vh",
      background: "#d6d6d6",
      display: "flex",
      justifyContent: "center",
      alignItems: "flex-start",
      padding: "32px 16px",
      fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    }}>
      <div style={{
        background: "#fff",
        borderRadius: 10,
        boxShadow: "0 4px 24px rgba(0,0,0,0.18)",
        overflow: "hidden",
        width: "100%",
        maxWidth: 480,
      }}>
        <div style={{
          background: "#34495e",
          color: "#fff",
          padding: "14px 20px",
          fontSize: 18,
          fontWeight: 700,
          letterSpacing: 1,
        }}>
          รายการสินค้า / Inventory
        </div>

        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "#ecf0f1" }}>
              <th style={{ padding: "10px 8px", width: 52, borderBottom: "2px solid #bdc3c7" }}></th>
              <th style={{ padding: "10px 8px", textAlign: "left", color: "#555", fontSize: 13, borderBottom: "2px solid #bdc3c7", width: 32 }}>#</th>
              <th style={{ padding: "10px 8px", textAlign: "left", color: "#555", fontSize: 13, borderBottom: "2px solid #bdc3c7" }}>รายงาน</th>
              <th style={{ padding: "10px 8px", textAlign: "center", color: "#555", fontSize: 13, borderBottom: "2px solid #bdc3c7", width: 90 }}>จำนวน</th>
            </tr>
          </thead>
          <tbody>
            {ITEMS.map((item, idx) => (
              <tr
                key={item.name}
                style={{ background: idx % 2 === 0 ? "#fff" : "#f5f6f7" }}
              >
                <td style={{ padding: "6px 8px", textAlign: "center", borderBottom: "1px solid #e8ecef" }}>
                  <img
                    src={ICONS[item.name]}
                    alt={item.label}
                    style={{ width: 40, height: 40, objectFit: "contain", display: "block", margin: "0 auto" }}
                  />
                </td>
                <td style={{ padding: "6px 8px", color: "#888", fontWeight: 600, fontSize: 13, borderBottom: "1px solid #e8ecef" }}>
                  {idx + 1}
                </td>
                <td style={{ padding: "6px 8px", fontWeight: 500, fontSize: 15, borderBottom: "1px solid #e8ecef" }}>
                  {item.label}
                </td>
                <td style={{ padding: "6px 8px", textAlign: "center", borderBottom: "1px solid #e8ecef" }}>
                  <input
                    type="number"
                    min="0"
                    value={quantities[item.name]}
                    onChange={e => setQuantities(q => ({ ...q, [item.name]: e.target.value }))}
                    placeholder="—"
                    style={{
                      width: 68,
                      padding: "4px 6px",
                      border: "1.5px solid #bdc3c7",
                      borderRadius: 6,
                      fontSize: 15,
                      textAlign: "center",
                      background: "#f9f9f9",
                      outline: "none",
                      color: "#2c3e50",
                    }}
                  />
                </td>
              </tr>
            ))}
          </tbody>
          <tfoot>
            <tr style={{ background: "#34495e" }}>
              <td colSpan={3} style={{ padding: "10px 8px", textAlign: "right", fontWeight: 700, fontSize: 16, color: "#fff" }}>
                รวม
              </td>
              <td style={{ padding: "10px 8px", textAlign: "center", fontWeight: 700, fontSize: 18, color: "#f1c40f" }}>
                {total || "—"}
              </td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>
  );
}
